// Output (monitor) tracking data
struct ImGui_ImplWayland_OutputData
{
    struct wl_output*               Output;
    struct zxdg_output_v1*          XdgOutput;
    uint32_t                        Name;           // Registry name for removal
    int32_t                         PosX;           // Logical position X
    int32_t                         PosY;           // Logical position Y
    int32_t                         Width;          // Logical width
    int32_t                         Height;         // Logical height
    int32_t                         Scale;          // Integer scale factor
    bool                            Done;           // Has received all initial events
    bool                            HasXdgOutput;   // Whether xdg-output info is available

    ImGui_ImplWayland_OutputData() { memset((void*)this, 0, sizeof(*this)); Scale = 1; }
};

// Per-viewport data for secondary viewports (main viewport uses data from init)
struct ImGui_ImplWayland_ViewportData
{
    struct wl_surface*              Surface;
    struct xdg_surface*             XdgSurface;
    struct xdg_toplevel*            Toplevel;
    struct wp_fractional_scale_v1*  FractionalScale;
    struct wp_viewport*             Viewport;
    struct wl_callback*             FrameCallback;

    uint32_t                        Width;
    uint32_t                        Height;
    uint32_t                        Scale;          // Fractional scale (base 120)
    float                           PosX;           // Logical position X (tracked internally since Wayland doesn't expose this)
    float                           PosY;           // Logical position Y
    float                           SavedPosX;      // Position before entering fullscreen
    float                           SavedPosY;
    bool                            Configured;
    bool                            WindowOwned;
    bool                            FrameDone;
    bool                            PendingResize;
    bool                            IsFullscreen;   // Whether this viewport is currently fullscreen
    int                             IgnoreWindowSizeEventFrame;
    int                             IgnoreWindowPosEventFrame;

    ImGui_ImplWayland_ViewportData() { memset((void*)this, 0, sizeof(*this)); Scale = 120; FrameDone = true; IgnoreWindowSizeEventFrame = -1; IgnoreWindowPosEventFrame = -1; }
};

// Backend data stored in io.BackendPlatformUserData
struct ImGui_ImplWayland_Data
{
    // Wayland globals (for creating secondary viewports)
    struct wl_display*                      Display;
    struct wl_compositor*                   Compositor;
    struct xdg_wm_base*                     WmBase;
    struct wl_seat*                         Seat;
    struct wp_fractional_scale_manager_v1*  FractionalScaleManager;
    struct wp_viewporter*                   Viewporter;
    struct wp_cursor_shape_manager_v1*      CursorShapeManager;

    // Main viewport surface and toplevel (not owned by us, provided by the application)
    struct wl_surface*                      MainSurface;
    struct xdg_toplevel*                    MainToplevel;

    // Timing
    timespec                                Time;

    // Main viewport metrics
    uint32_t                                DisplayWidth;
    uint32_t                                DisplayHeight;
    uint32_t                                BufferWidth;
    uint32_t                                BufferHeight;
    uint32_t                                FractionalScale; // Numerator for framebuffer scale (denominator 120)
    uint32_t                                InputScale;      // Numerator for input coordinate scale (denominator 120)

    // Legacy window pointer (for cursor callback compatibility)
    WaylandWSIWindow                        Window;
    ImGui_ImplWayland_SetCursorFunc         SetCursorFunc;

    // Mouse handling
    int                                     MouseButtonsDown;
    ImGuiMouseCursor                        LastMouseCursor;
    struct wl_surface*                      MouseSurface;    // Surface that currently has pointer focus
    uint32_t                                PointerSerial;   // Serial from last pointer button event (for drag initiation)
    uint32_t                                PointerEnterSerial; // Serial from last pointer enter event (for cursor shape)
    double                                  MouseLocalX;     // Local surface coordinates of pointer (for drag offset)
    double                                  MouseLocalY;

    // Multi-viewport support
    bool                                    MultiViewportEnabled;

    // Toplevel drag state machine (similar to Chromium's approach)
    // States: kIdle -> kAttached -> kDetached -> kDropped/kCancelled -> kIdle
    enum class DragState {
        kIdle,       // No drag in progress
        kAttached,   // DnD session started, waiting for detach (window to be dragged)
        kDetached,   // Window attached and being dragged
        kDropped,    // Drop completed successfully
        kCancelled,  // Drag was cancelled
    };
    DragState                               DragSessionState;

    // Toplevel drag support
    struct wl_data_device_manager*          DataDeviceManager;
    struct wl_data_device*                  DataDevice;
    struct xdg_toplevel_drag_manager_v1*    ToplevelDragManager;
    struct wl_data_source*                  ActiveDataSource;
    struct xdg_toplevel_drag_v1*            ActiveToplevelDrag;
    struct xdg_toplevel*                    DraggedToplevel;     // Toplevel currently attached to drag
    struct wl_data_offer*                   CurrentDataOffer;    // Current data offer during drag (for cleanup)
    struct wl_surface*                      DragEnterSurface;    // Surface the drag is currently over
    struct wl_surface*                      DragOriginSurface;   // Surface where drag started
    int32_t                                 DragOffsetX;         // Offset used when attaching toplevel to drag
    int32_t                                 DragOffsetY;
    double                                  DragCursorX;         // Current drag cursor position (relative to enter surface)
    double                                  DragCursorY;
    bool                                    DragInProgress;      // Legacy flag, maps to state != kIdle
    bool                                    DragFinished;        // Legacy flag, prevents retry with same serial
    bool                                    HasReceivedEnter;    // True once we've received at least one enter event

    // Output (monitor) management
    struct zxdg_output_manager_v1*          XdgOutputManager;
    struct zwlr_output_manager_v1*          WlrOutputManager;
    ImVector<ImGui_ImplWayland_OutputData*> Outputs;
    bool                                    MonitorsDirty;

    ImGui_ImplWayland_Data() { memset((void*)this, 0, sizeof(*this)); FractionalScale = 120; InputScale = 120; }
};



#include <cmath>
#include <cfloat>
#include <time.h>

/**
 * @brief Normalize a tv_sec, tv_nsec pair into a timespec such that tv_nsec is in the range [0, 999999999]
 * 
 * Per the timespec specification, tv_nsec should be positive, in the range 0 to 999,999,999. It is always
 * added to tv_sec (even when tv_sec is negative).
 * For this reason, if t is the time in secs, tv_sec is actually floor(t), and nsec is (t - floor(t)) * 1.0e9.
 * 
 * @param tv_sec   (long) time in seconds. Msy be negative.
 * @param tv_nsec  (long) time in nanoseconds to be added to tv_sec. May be negative or >= 1000000000.
 * 
 * @return timespec  Normalized timespec value with tv_nsec in the range [0, 999999999]
 */
inline static struct timespec normalize_timespec(long tv_sec, long tv_nsec) {
    long const billion = 1000000000;
    struct timespec t;
    t.tv_sec = (tv_nsec >= 0 ? tv_nsec : tv_nsec - (billion-1)) / billion;
    t.tv_nsec = tv_nsec - t.tv_sec * billion;
    t.tv_sec += tv_sec;
    return t;
}

/**
 * @brief Subtract two timespec values
 * 
 * @param time1 Ending time
 * @param time0 Starting time
 * @return timespec  (time1 - time0)
 */
inline static struct timespec timespec_subtract(const struct timespec& time1, const struct timespec& time0) {
    return normalize_timespec(time1.tv_sec - time0.tv_sec, time1.tv_nsec - time0.tv_nsec);
}

/**
 * @brief Add two timespec values
 * 
 * @param time1 Ending time
 * @param time0 Starting time
 * @return timespec  (time1 + time0)
 */
inline static struct timespec timespec_add(const struct timespec& time1, const struct timespec& time2) {
    return normalize_timespec(time1.tv_sec + time2.tv_sec, time1.tv_nsec + time2.tv_nsec);
}

/**
 * @brief Convert a timespec to a double in seconds
 * 
 * @param ts 
 * @return double 
 */
inline double timespec_to_secs(const struct timespec& ts) {
    return (double)ts.tv_sec + (double)ts.tv_nsec / 1.0e9;
}

/**
 * @brief Convert a double in seconds to a timespec
 */
inline struct timespec secs_to_timespec(double secs) {
    auto sec = (long)floor(secs);
    auto nsec = (long)round((secs - (double)sec) * 1.0e9);
    return normalize_timespec(sec, nsec);
}

// Backend data stored in io.BackendPlatformUserData to allow support for multiple Dear ImGui contexts
// It is STRONGLY preferred that you use docking branch with multi-viewports (== single Dear ImGui context + multiple windows) instead of multiple Dear ImGui contexts.
// FIXME: multi-context support is not well tested and probably dysfunctional in this backend.
// FIXME: some shared resources (mouse cursor shape, gamepad) are mishandled when using multi-context.
static ImGui_ImplWayland_Data* ImGui_ImplWayland_GetBackendData()
{
    return ImGui::GetCurrentContext() ? (ImGui_ImplWayland_Data*)ImGui::GetIO().BackendPlatformUserData : nullptr;
}

