// Convert a UTF8 code point to a C string
uint32_t ImGui_ImplWayland_UTF8CodePointToString(uint32_t code_point, char *output) {
    uint32_t len = 0;

    if (code_point < 0x80) {
        output[0] = (char)code_point;
        len = 1;
    } else if (code_point < 0x800) {
        output[0] = 0xC0 | (code_point >> 6);
        output[1] = 0x80 | (code_point & 0x3F);
        len = 2;
    } else if (code_point < 0x10000) {
        output[0] = 0xE0 | (code_point >> 12);
        output[1] = 0x80 | ((code_point >> 6) & 0x3F);
        output[2] = 0x80 | (code_point & 0x3F);
        len = 3;
    } else if (code_point < 0x110000) {
        output[0] = 0xF0 | (code_point >> 18);
        output[1] = 0x80 | ((code_point >> 12) & 0x3F);
        output[2] = 0x80 | ((code_point >> 6) & 0x3F);
        output[3] = 0x80 | (code_point & 0x3F);
        len = 4;
    } else {
        // Invalid code point - use replacement character
        output[0] = (char) 0xEF;
        output[1] = (char) 0xBF;
        output[2] = (char) 0xBD;
        output[3] = 0;
        return 0;
    }
    // null-terminate
    output[len] = 0;
    return len;
}

