// You can read the io.WantCaptureMouse, io.WantCaptureKeyboard flags to tell if dear imgui wants to use your inputs.
// - When io.WantCaptureMouse is true, do not dispatch mouse input data to your main application, or clear/overwrite your copy of the mouse data.
// - When io.WantCaptureKeyboard is true, do not dispatch keyboard input data to your main application, or clear/overwrite your copy of the keyboard data.
// Generally you may always pass all inputs to dear imgui, and hide them from your application based on those two flags.
// If you have multiple SDL events and some of them are not meant to be used by dear imgui, you may need to filter events based on their windowID field.
bool ImGui_ImplWayland_ProcessEvent(const Input_Event *event)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    IM_ASSERT(bd != nullptr && "Context or backend not initialized! Did you call ImGui_ImplSDL3_Init()?");
    ImGuiIO& io = ImGui::GetIO();
    switch (event->type)
    {
        case INPUT_EVENT_POINTER_MOTION:
        {
            // Wayland provides coordinates in logical (surface) coordinates
            // Scale by InputScale for native resolution rendering
            float inputScale = bd->InputScale / WAYLAND_SCALE_FACTOR;
            io.AddMouseSourceEvent(ImGuiMouseSource_Mouse);
            io.AddMousePosEvent((float)event->pointer_motion.x * inputScale, (float)event->pointer_motion.y * inputScale);
            return true;
        }
        case INPUT_EVENT_POINTER_AXIS:
        {
            float wheel_x = 0.0, wheel_y = 0.0;
            if (event->pointer_axis.axis == WL_POINTER_AXIS_HORIZONTAL_SCROLL) {
               wheel_x = event->pointer_axis.value;
            }
            else if (event->pointer_axis.axis == WL_POINTER_AXIS_VERTICAL_SCROLL) {
               wheel_y = -event->pointer_axis.value;
            } else {
                IM_ASSERT(false && "wayland: invalid pointer axis");
            }
            io.AddMouseSourceEvent(ImGuiMouseSource_Mouse);
            io.AddMouseWheelEvent(wheel_x, wheel_y);
            return true;
        }
        case INPUT_EVENT_POINTER_BUTTON:
        {
            int mouse_button = -1;
            if (event->pointer_button.button == BTN_LEFT) { mouse_button = 0; }
            if (event->pointer_button.button == BTN_RIGHT) { mouse_button = 1; }
            if (event->pointer_button.button == BTN_MIDDLE) { mouse_button = 2; }
            if (event->pointer_button.button == BTN_SIDE) { mouse_button = 3; }
            if (event->pointer_button.button == BTN_EXTRA) { mouse_button = 4; }
            if (event->pointer_button.button == BTN_FORWARD) { mouse_button = 5; }
            if (event->pointer_button.button == BTN_BACK) { mouse_button = 6; }
            if (event->pointer_button.button == BTN_TASK) { mouse_button = 7; }
            if (mouse_button == -1)
                break;

            // Capture the serial from button press events - needed for drag initiation
            if (event->pointer_button.pressed && event->pointer_button.serial != 0)
            {
                bd->PointerSerial = event->pointer_button.serial;
                bd->DragFinished = false;  // Reset so we can try a new drag with this serial
            }

            io.AddMouseSourceEvent(ImGuiMouseSource_Mouse);
            io.AddMouseButtonEvent(mouse_button, event->pointer_button.pressed);
            bd->MouseButtonsDown = event->pointer_button.pressed ? (bd->MouseButtonsDown | (1 << mouse_button)) : (bd->MouseButtonsDown & ~(1 << mouse_button));

            return true;
        }
    //     case SDL_EVENT_TEXT_INPUT:
    //     {
    //         if (ImGui_ImplSDL3_GetViewportForWindowID(event->text.windowID) == nullptr)
    //             return false;
            // io.AddInputCharactersUTF8(event->text.text);
            // return true;
    //     }
        case INPUT_EVENT_KEYBOARD_KEY:
        {
            // if (ImGui_ImplSDL3_GetViewportForWindowID(event->key.windowID) == nullptr)
            //     return false;
            // IMGUI_DEBUG_LOG("SDL_EVENT_KEY_%d: key=%d, scancode=%d, mod=%X\n", (event->type == SDL_EVENT_KEY_DOWN) ? "DOWN" : "UP", event->key.key, event->key.scancode, event->key.mod);
            // ImGui_ImplSDL3_UpdateKeyModifiers((SDL_Keymod)event->key.mod);
            // 
            ImGuiKey key = ImGui_ImplWayland_XKBKeyCodeToImGuiKey(event->keyboard_key.key);
            io.AddKeyEvent(key, event->keyboard_key.pressed);
            if (event->keyboard_key.pressed && event->keyboard_key.unicode > 0) {
                char unicodeChar[5];
                ImGui_ImplWayland_UTF8CodePointToString(event->keyboard_key.unicode, unicodeChar);
                io.AddInputCharactersUTF8((char *)unicodeChar);
            }
            // io.SetKeyEventNativeData(key, event->key.key, event->key.scancode, event->key.scancode); // To support legacy indexing (<1.87 user code). Legacy backend uses SDLK_*** as indices to IsKeyXXX() functions.
            return true;
        }
        case INPUT_EVENT_KEYBOARD_MODIFIERS:
            // IMGUI_DEBUG_LOG("SDL_EVENT_KEY_%d: key=%d, scancode=%d, mod=%X\n", (event->type == SDL_EVENT_KEY_DOWN) ? "DOWN" : "UP", event->key.key, event->key.scancode, event->key.mod);
            ImGui_ImplWayland_UpdateKeyModifiers(0);
        case INPUT_EVENT_POINTER_ENTER:
        {
            // Wayland provides coordinates in logical (surface) coordinates
            // Scale by InputScale for native resolution rendering
            float inputScale = bd->InputScale / WAYLAND_SCALE_FACTOR;
            io.AddMouseSourceEvent(ImGuiMouseSource_Mouse);
            io.AddMousePosEvent((float)event->pointer_enter.x * inputScale, (float)event->pointer_enter.y * inputScale);
            return true;
        }
        case INPUT_EVENT_POINTER_EXIT:
        {
            return true;
        }
    //     case SDL_EVENT_WINDOW_FOCUS_GAINED:
    //     case SDL_EVENT_WINDOW_FOCUS_LOST:
    //     {
    //         if (ImGui_ImplSDL3_GetViewportForWindowID(event->window.windowID) == nullptr)
    //             return false;
    //         io.AddFocusEvent(event->type == SDL_EVENT_WINDOW_FOCUS_GAINED);
    //         return true;
    //     }
    //     case SDL_EVENT_GAMEPAD_ADDED:
    //     case SDL_EVENT_GAMEPAD_REMOVED:
    //     {
    //         bd->WantUpdateGamepadsList = true;
    //         return true;
    //     }
    }
    return false;
}

