// Multi-viewport initialization (recommended for full multi-viewport support)
bool ImGui_ImplWayland_InitMultiViewport(const ImGui_ImplWayland_InitData* init_data)
{
    ImGuiIO& io = ImGui::GetIO();
    IMGUI_CHECKVERSION();
    IM_ASSERT(io.BackendPlatformUserData == nullptr && "Already initialized a platform backend!");
    IM_ASSERT(init_data->Display != nullptr && "Wayland display is required!");
    IM_ASSERT(init_data->MainSurface != nullptr && "Main surface is required!");
    IM_ASSERT(init_data->Compositor != nullptr && "Compositor is required for multi-viewport!");
    IM_ASSERT(init_data->WmBase != nullptr && "xdg_wm_base is required for multi-viewport!");

    // Setup backend capabilities flags
    ImGui_ImplWayland_Data* bd = IM_NEW(ImGui_ImplWayland_Data)();
    io.BackendPlatformUserData = (void*)bd;
    io.BackendPlatformName = "imgui_impl_wayland";
    io.BackendFlags |= ImGuiBackendFlags_HasMouseCursors;           // We can honor GetMouseCursor() values
    io.BackendFlags |= ImGuiBackendFlags_PlatformHasViewports;      // We can create multi-viewports
    io.BackendFlags |= ImGuiBackendFlags_HasMouseHoveredViewport;   // We can call AddMouseViewportEvent() with the viewport under the mouse

    // Store Wayland globals
    bd->Display = init_data->Display;
    bd->MainSurface = init_data->MainSurface;
    bd->MainToplevel = init_data->MainToplevel;
    bd->Compositor = init_data->Compositor;
    bd->WmBase = init_data->WmBase;
    bd->Seat = init_data->Seat;
    bd->FractionalScaleManager = init_data->FractionalScaleManager;
    bd->Viewporter = init_data->Viewporter;
    bd->CursorShapeManager = init_data->CursorShapeManager;
    bd->DataDeviceManager = init_data->DataDeviceManager;
    bd->ToplevelDragManager = init_data->ToplevelDragManager;
    bd->XdgOutputManager = init_data->XdgOutputManager;

    // Legacy cursor callback support
    bd->Window = init_data->SetCursorFuncUserData;
    bd->SetCursorFunc = init_data->SetCursorFunc;

    // Store initial metrics
    ImGui_ImplWayland_UpdateFrameMetrics(&init_data->Metrics);

    bd->MultiViewportEnabled = true;

    // Initialize multi-viewport support
    ImGui_ImplWayland_InitMultiViewportSupport();

    return true;
}

// Legacy single-viewport initialization
bool ImGui_ImplWayland_Init(const ImGui_ImplWayland_ConfigurationData *configData)
{
    ImGuiIO& io = ImGui::GetIO();
    IMGUI_CHECKVERSION();
    IM_ASSERT(io.BackendPlatformUserData == nullptr && "Already initialized a platform backend!");

    // Setup backend capabilities flags
    ImGui_ImplWayland_Data* bd = IM_NEW(ImGui_ImplWayland_Data)();
    io.BackendPlatformUserData = (void*)bd;
    io.BackendPlatformName = "imgui_impl_wayland";
    io.BackendFlags |= ImGuiBackendFlags_HasMouseCursors;           // We can honor GetMouseCursor() values (optional)

    bd->Window = configData->window;
    bd->SetCursorFunc = configData->setCursorFunc;
    bd->MultiViewportEnabled = false;

    ImGui_ImplWayland_UpdateFrameMetrics(&configData->metrics);

    return true;
}

void ImGui_ImplWayland_Shutdown()
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    IM_ASSERT(bd != nullptr && "No platform backend to shutdown, or already shutdown?");
    ImGuiIO& io = ImGui::GetIO();

    // Shutdown multi-viewport support
    if (bd->MultiViewportEnabled)
        ImGui_ImplWayland_ShutdownMultiViewportSupport();

    // Clean up drag-related resources
    if (bd->CurrentDataOffer)
    {
        wl_data_offer_destroy(bd->CurrentDataOffer);
        bd->CurrentDataOffer = nullptr;
    }
    if (bd->ActiveToplevelDrag)
    {
        xdg_toplevel_drag_v1_destroy(bd->ActiveToplevelDrag);
        bd->ActiveToplevelDrag = nullptr;
    }
    if (bd->ActiveDataSource)
    {
        wl_data_source_destroy(bd->ActiveDataSource);
        bd->ActiveDataSource = nullptr;
    }
    if (bd->DataDevice)
    {
        wl_data_device_release(bd->DataDevice);
        bd->DataDevice = nullptr;
    }

    io.BackendPlatformName = nullptr;
    io.BackendPlatformUserData = nullptr;
    io.BackendFlags &= ~(ImGuiBackendFlags_HasMouseCursors | ImGuiBackendFlags_HasSetMousePos | ImGuiBackendFlags_PlatformHasViewports);
    IM_DELETE(bd);
}

