void ImGui_ImplWayland_UpdateFrameMetrics(const ImGui_ImplWayland_FrameMetrics *metrics)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    IM_ASSERT(bd != nullptr && "Platform backend not initialised");
    bd->DisplayWidth = metrics->DisplayWidth;
    bd->DisplayHeight = metrics->DisplayHeight;
    bd->BufferWidth = metrics->BufferWidth;
    bd->BufferHeight = metrics->BufferHeight;
    bd->FractionalScale = metrics->FractionalScale;
    bd->InputScale = metrics->InputScale;

    // Update main viewport's ViewportData to keep FramebufferScale in sync
    // This is important for multi-viewport mode where Platform_GetWindowFramebufferScale
    // reads from the ViewportData rather than bd->FractionalScale directly
    if (bd->MultiViewportEnabled)
    {
        ImGuiViewport* main_viewport = ImGui::GetMainViewport();
        if (main_viewport && main_viewport->PlatformUserData)
        {
            ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)main_viewport->PlatformUserData;
            vd->Width = metrics->DisplayWidth;
            vd->Height = metrics->DisplayHeight;
            vd->Scale = metrics->FractionalScale;
        }
    }
}

static void ImGui_ImplWayland_UpdateMouseCursor()
{
    ImGuiIO& io = ImGui::GetIO();
    if (io.ConfigFlags & ImGuiConfigFlags_NoMouseCursorChange)
        return;
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();

    // Skip cursor update if no callback is provided
    if (bd->SetCursorFunc == nullptr)
        return;

    ImGuiMouseCursor imgui_cursor = ImGui::GetMouseCursor();
    if (bd->LastMouseCursor == imgui_cursor) {
        return;
    }

    bool visible = io.MouseDrawCursor || imgui_cursor != ImGuiMouseCursor_None;
    IM_ASSERT(bd->Window != NULL);
    bd->SetCursorFunc(bd->Window, imgui_cursor, visible);
    bd->LastMouseCursor = imgui_cursor;
}

