void ImGui_ImplWayland_NewFrame()
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    IM_ASSERT(bd != nullptr && "Context or backend not initialized! Did you call ImGui_ImplWayland_Init()?");
    ImGuiIO& io = ImGui::GetIO();

    // Update monitors if changed (for multi-viewport support)
    if (bd->MultiViewportEnabled && bd->MonitorsDirty)
        ImGui_ImplWayland_UpdateMonitors();

    // Setup display size (every frame to accommodate for window resizing)
    // Use logical coordinates with exact buffer/display ratio for FramebufferScale
    // This keeps UI elements consistent across different display scales
    float scaleX = (bd->DisplayWidth > 0) ? (float)bd->BufferWidth / (float)bd->DisplayWidth : 1.0f;
    float scaleY = (bd->DisplayHeight > 0) ? (float)bd->BufferHeight / (float)bd->DisplayHeight : 1.0f;
    io.DisplaySize = ImVec2((float)bd->DisplayWidth, (float)bd->DisplayHeight);
    io.DisplayFramebufferScale = ImVec2(scaleX, scaleY);

    timespec current_time;
    int res = clock_gettime(CLOCK_MONOTONIC, &current_time);
    if (res == 0) {
        timespec delta_spec = timespec_subtract(current_time, bd->Time);
        double delta_time = timespec_to_secs(delta_spec);
        io.DeltaTime = delta_time;
        bd->Time = current_time;
    } else {
        io.DeltaTime = (float)(1.0f / 60.0f);
    }

    ImGui_ImplWayland_UpdateMouseCursor();
}

// Helper function to find viewport by Wayland surface
static ImGuiViewport* ImGui_ImplWayland_FindViewportBySurface(struct wl_surface* surface)
{
    if (surface == nullptr)
        return nullptr;

    ImGuiPlatformIO& platform_io = ImGui::GetPlatformIO();
    for (int i = 0; i < platform_io.Viewports.Size; i++)
    {
        ImGuiViewport* vp = platform_io.Viewports[i];
        ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)vp->PlatformUserData;
        if (vd && vd->Surface == surface)
            return vp;
    }
    // Debug: surface not found
    printf("[Input] FindViewportBySurface: surface=%p NOT FOUND among %d viewports:\n", (void*)surface, platform_io.Viewports.Size);
    for (int i = 0; i < platform_io.Viewports.Size; i++)
    {
        ImGuiViewport* vp = platform_io.Viewports[i];
        ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)vp->PlatformUserData;
        printf("  [%d] viewport_id=0x%X, surface=%p, vd=%p\n", i, vp->ID, vd ? (void*)vd->Surface : nullptr, (void*)vd);
    }
    return nullptr;
}

// Helper function to find viewport by xdg_toplevel
static ImGuiViewport* ImGui_ImplWayland_FindViewportByToplevel(struct xdg_toplevel* toplevel)
{
    if (toplevel == nullptr)
        return nullptr;

    ImGuiPlatformIO& platform_io = ImGui::GetPlatformIO();
    for (int i = 0; i < platform_io.Viewports.Size; i++)
    {
        ImGuiViewport* vp = platform_io.Viewports[i];
        ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)vp->PlatformUserData;
        if (vd && vd->Toplevel == toplevel)
            return vp;
    }
    return nullptr;
}

// Update position of viewport being dragged based on global mouse position.
// During xdg_toplevel_drag, the compositor moves the window but doesn't tell us where.
// We calculate the position from: window_pos = mouse_pos - drag_offset
// This is essential for ImGui to correctly calculate dock preview target positions.
static void ImGui_ImplWayland_UpdateDraggedViewportPosition(float global_mouse_x, float global_mouse_y)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    if (!bd || !bd->DragInProgress || !bd->DraggedToplevel)
        return;

    // Find the viewport being dragged
    ImGuiViewport* vp = ImGui_ImplWayland_FindViewportByToplevel(bd->DraggedToplevel);
    if (!vp)
        return;

    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)vp->PlatformUserData;
    if (!vd)
        return;

    // Calculate window position from mouse position and drag offset
    // window_pos = mouse_pos - drag_offset
    float new_pos_x = global_mouse_x - (float)bd->DragOffsetX;
    float new_pos_y = global_mouse_y - (float)bd->DragOffsetY;

    // Update tracked position so GetWindowPos returns correct value
    vd->PosX = new_pos_x;
    vd->PosY = new_pos_y;
}

// Multi-viewport: Process event for a specific surface
bool ImGui_ImplWayland_ProcessEventForSurface(const Input_Event *event, struct wl_surface* surface)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    if (bd == nullptr)
        return false;

    ImGuiIO& io = ImGui::GetIO();

    // Find the viewport for this surface
    ImGuiViewport* viewport = ImGui_ImplWayland_FindViewportBySurface(surface);
    if (viewport == nullptr)
        viewport = ImGui::GetMainViewport();

    // Track which surface has pointer focus and local coordinates
    if (event->type == INPUT_EVENT_POINTER_ENTER)
    {
        bd->MouseSurface = surface;
        bd->MouseLocalX = event->pointer_enter.x;
        bd->MouseLocalY = event->pointer_enter.y;
        bd->PointerEnterSerial = event->pointer_enter.serial;
        // Invalidate cached cursor to force re-setting cursor on enter
        // Wayland requires cursor to be set on each pointer enter event
        bd->LastMouseCursor = ImGuiMouseCursor_COUNT;
        printf("[Input] POINTER_ENTER: surface=%p, viewport_id=0x%X, local=(%.1f, %.1f), vp_pos=(%.1f, %.1f), vp_size=(%.1f, %.1f)\n",
               (void*)surface, viewport->ID, event->pointer_enter.x, event->pointer_enter.y,
               viewport->Pos.x, viewport->Pos.y, viewport->Size.x, viewport->Size.y);
    }
    else if (event->type == INPUT_EVENT_POINTER_MOTION)
    {
        bd->MouseLocalX = event->pointer_motion.x;
        bd->MouseLocalY = event->pointer_motion.y;
    }
    else if (event->type == INPUT_EVENT_POINTER_EXIT)
    {
        bd->MouseSurface = nullptr;
        bd->MouseLocalX = 0;
        bd->MouseLocalY = 0;
    }

    // For mouse events with multi-viewport enabled, we need to:
    // 1. Set MouseHoveredViewport so ImGui knows which viewport the mouse is over
    // 2. Transform local surface coordinates to global coordinates by adding viewport position
    if (io.ConfigFlags & ImGuiConfigFlags_ViewportsEnable)
    {
        switch (event->type)
        {
            case INPUT_EVENT_POINTER_ENTER:
            {
                io.AddMouseViewportEvent(viewport->ID);
                // Transform local coords to global by adding viewport position
                // Wayland gives us logical coordinates, ImGui works in logical coordinates
                // so no scaling needed - just add viewport position for global coords
                float x = (float)event->pointer_enter.x + viewport->Pos.x;
                float y = (float)event->pointer_enter.y + viewport->Pos.y;
                printf("[Input] ENTER global: (%.1f, %.1f) = local (%.1f, %.1f) + vp_pos (%.1f, %.1f)\n",
                       x, y, event->pointer_enter.x, event->pointer_enter.y, viewport->Pos.x, viewport->Pos.y);
                io.AddMouseSourceEvent(ImGuiMouseSource_Mouse);
                io.AddMousePosEvent(x, y);
                return true;
            }
            case INPUT_EVENT_POINTER_MOTION:
            {
                io.AddMouseViewportEvent(viewport->ID);
                // Transform local coords to global by adding viewport position
                // Wayland gives us logical coordinates, ImGui works in logical coordinates
                // so no scaling needed - just add viewport position for global coords
                float x = (float)event->pointer_motion.x + viewport->Pos.x;
                float y = (float)event->pointer_motion.y + viewport->Pos.y;
                io.AddMouseSourceEvent(ImGuiMouseSource_Mouse);
                io.AddMousePosEvent(x, y);

                // If a viewport is being dragged via xdg_toplevel_drag, update its tracked position
                // based on the global mouse position and the drag offset
                ImGui_ImplWayland_UpdateDraggedViewportPosition(x, y);
                return true;
            }
            case INPUT_EVENT_POINTER_EXIT:
            {
                // When leaving a surface, report invalid position
                io.AddMousePosEvent(-FLT_MAX, -FLT_MAX);
                return true;
            }
            case INPUT_EVENT_POINTER_BUTTON:
                printf("[Input] POINTER_BUTTON: surface=%p, viewport_id=0x%X, pressed=%d, io.MousePos=(%.1f, %.1f), viewport->Pos=(%.1f, %.1f)\n",
                       (void*)surface, viewport->ID, event->pointer_button.pressed,
                       io.MousePos.x, io.MousePos.y, viewport->Pos.x, viewport->Pos.y);
                io.AddMouseViewportEvent(viewport->ID);
                break;
            case INPUT_EVENT_POINTER_AXIS:
            case INPUT_EVENT_POINTER_FRAME:
                io.AddMouseViewportEvent(viewport->ID);
                break;
            default:
                break;
        }
    }

    // Process the event (this updates ImGuiIO for non-position events)
    return ImGui_ImplWayland_ProcessEvent(event);
}

