// Fractional scale event listener for secondary viewports
static void ImGui_ImplWayland_ViewportFractionalScalePreferredScale(void* data, struct wp_fractional_scale_v1* /*scale*/, uint32_t new_scale)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)data;
    if (vd->Scale != new_scale)
    {
        vd->Scale = new_scale;
        vd->PendingResize = true;  // Scale change requires buffer resize

        // Update viewporter destination to match new scale
        // This tells the compositor the logical size so it can scale our buffer appropriately
        if (vd->Viewport)
            wp_viewport_set_destination(vd->Viewport, (int32_t)vd->Width, (int32_t)vd->Height);
    }
}

static const struct wp_fractional_scale_v1_listener ImGui_ImplWayland_ViewportFractionalScaleListener = {
    .preferred_scale = ImGui_ImplWayland_ViewportFractionalScalePreferredScale,
};

// Wayland xdg_surface configure callback for secondary viewports
static void ImGui_ImplWayland_XdgSurfaceConfigure(void* data, struct xdg_surface* surface, uint32_t serial)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)data;
    xdg_surface_ack_configure(surface, serial);
    vd->Configured = true;
}

static const struct xdg_surface_listener ImGui_ImplWayland_XdgSurfaceListener = {
    .configure = ImGui_ImplWayland_XdgSurfaceConfigure,
};

// Wayland xdg_toplevel configure callback for secondary viewports
static void ImGui_ImplWayland_XdgToplevelConfigure(void* data, struct xdg_toplevel* toplevel, int32_t width, int32_t height, struct wl_array* states)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)data;

    // Parse states array to detect fullscreen
    bool is_fullscreen = false;
    for (uint32_t* state = (uint32_t*)states->data;
         (const char*)state < ((const char*)states->data + states->size);
         state++)
    {
        if (*state == XDG_TOPLEVEL_STATE_FULLSCREEN)
            is_fullscreen = true;
    }

    // Handle fullscreen state changes - unset parent when fullscreen to allow
    // other windows to receive input (important for multi-monitor setups)
    if (vd->IsFullscreen != is_fullscreen)
    {
        vd->IsFullscreen = is_fullscreen;

        // Find the viewport to update its position
        ImGuiPlatformIO& platform_io = ImGui::GetPlatformIO();
        ImGuiViewport* vp = nullptr;
        for (int i = 0; i < platform_io.Viewports.Size; i++)
        {
            if (platform_io.Viewports[i]->PlatformUserData == vd)
            {
                vp = platform_io.Viewports[i];
                break;
            }
        }

        if (is_fullscreen)
        {
            // Unset parent so this fullscreen window doesn't block input to others
            xdg_toplevel_set_parent(toplevel, nullptr);

            // Save current position and reset to (0,0) for fullscreen
            // TODO: For multi-monitor, determine which monitor and use its origin
            vd->SavedPosX = vd->PosX;
            vd->SavedPosY = vd->PosY;
            vd->PosX = 0;
            vd->PosY = 0;

            printf("[Fullscreen] Entering fullscreen: saved pos (%.1f, %.1f), new pos (0, 0)\n",
                   vd->SavedPosX, vd->SavedPosY);

            // Notify ImGui that position changed
            if (vp)
                vp->PlatformRequestMove = true;
        }
        else
        {
            // Restore parent relationship when exiting fullscreen
            if (bd->MainToplevel)
                xdg_toplevel_set_parent(toplevel, bd->MainToplevel);

            // Restore saved position
            vd->PosX = vd->SavedPosX;
            vd->PosY = vd->SavedPosY;

            printf("[Fullscreen] Exiting fullscreen: restored pos (%.1f, %.1f)\n",
                   vd->PosX, vd->PosY);

            // Notify ImGui that position changed
            if (vp)
                vp->PlatformRequestMove = true;
        }
    }

    // width/height of 0 means "use your preferred size" - keep our initial size
    if (width > 0 && height > 0)
    {
        if (vd->Width != (uint32_t)width || vd->Height != (uint32_t)height)
        {
            vd->Width = width;
            vd->Height = height;
            vd->PendingResize = true;

            // Update viewporter destination to tell compositor the logical size
            if (vd->Viewport)
                wp_viewport_set_destination(vd->Viewport, width, height);

            // Notify ImGui that compositor changed our size
            // Find the viewport for this toplevel and set PlatformRequestResize
            ImGuiPlatformIO& platform_io = ImGui::GetPlatformIO();
            for (int i = 0; i < platform_io.Viewports.Size; i++)
            {
                ImGuiViewport* vp = platform_io.Viewports[i];
                ImGui_ImplWayland_ViewportData* vp_vd = (ImGui_ImplWayland_ViewportData*)vp->PlatformUserData;
                if (vp_vd && vp_vd->Toplevel == toplevel)
                {
                    // Only set resize flag if we didn't just request this size ourselves
                    if (vp_vd->IgnoreWindowSizeEventFrame != ImGui::GetFrameCount())
                        vp->PlatformRequestResize = true;
                    break;
                }
            }
        }
    }
}

static void ImGui_ImplWayland_XdgToplevelClose(void* data, struct xdg_toplevel* toplevel)
{
    // Find the viewport and request close
    ImGuiPlatformIO& platform_io = ImGui::GetPlatformIO();
    for (int i = 0; i < platform_io.Viewports.Size; i++)
    {
        ImGuiViewport* vp = platform_io.Viewports[i];
        ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)vp->PlatformUserData;
        if (vd && vd->Toplevel == toplevel)
        {
            vp->PlatformRequestClose = true;
            break;
        }
    }
}

