static void ImGui_ImplWayland_CreateWindow(ImGuiViewport* viewport)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    ImGui_ImplWayland_ViewportData* vd = IM_NEW(ImGui_ImplWayland_ViewportData)();
    viewport->PlatformUserData = vd;

    // Store initial size - use main viewport scale as initial value
    vd->Width = (uint32_t)viewport->Size.x;
    vd->Height = (uint32_t)viewport->Size.y;
    vd->Scale = bd->FractionalScale;  // Inherit main viewport scale initially
    vd->PosX = viewport->Pos.x;       // Track initial position for coordinate transforms
    vd->PosY = viewport->Pos.y;
    vd->WindowOwned = true;

    // Create Wayland surface
    vd->Surface = wl_compositor_create_surface(bd->Compositor);
    if (!vd->Surface)
    {
        IM_ASSERT(0 && "Failed to create Wayland surface for viewport");
        return;
    }

    // Create xdg_surface
    vd->XdgSurface = xdg_wm_base_get_xdg_surface(bd->WmBase, vd->Surface);
    xdg_surface_add_listener(vd->XdgSurface, &ImGui_ImplWayland_XdgSurfaceListener, vd);

    // Create xdg_toplevel
    vd->Toplevel = xdg_surface_get_toplevel(vd->XdgSurface);
    xdg_toplevel_add_listener(vd->Toplevel, &ImGui_ImplWayland_XdgToplevelListener, vd);

    // Set the main viewport as parent so secondary viewports appear above it
    // This helps compositors stack windows correctly and keep popups/secondary
    // windows associated with the main application window
    if (bd->MainToplevel)
        xdg_toplevel_set_parent(vd->Toplevel, bd->MainToplevel);

    // Set window properties based on viewport flags
    if (viewport->Flags & ImGuiViewportFlags_NoDecoration)
    {
        // Request server-side decorations to be disabled
        // Note: This requires xdg-decoration protocol which we haven't added yet
    }

    // Set app_id for the secondary window
    xdg_toplevel_set_app_id(vd->Toplevel, "imgui_viewport");

    // Set reasonable size constraints to allow resizing
    // We set a minimum size but leave max at 0 (unlimited) so the user can resize
    // NOTE: If ImGuiViewportFlags_NoInputs or similar is set, we might want fixed size,
    // but for now we allow resizing of all secondary viewports.
    xdg_toplevel_set_min_size(vd->Toplevel, 50, 50);  // Reasonable minimum
    xdg_toplevel_set_max_size(vd->Toplevel, 0, 0);    // 0 = unlimited

    // Set up fractional scaling if available (must be done before first commit)
    if (bd->FractionalScaleManager)
    {
        vd->FractionalScale = wp_fractional_scale_manager_v1_get_fractional_scale(bd->FractionalScaleManager, vd->Surface);
        wp_fractional_scale_v1_add_listener(vd->FractionalScale, &ImGui_ImplWayland_ViewportFractionalScaleListener, vd);
    }

    // Set up viewporter if available (for precise buffer scaling)
    if (bd->Viewporter)
    {
        vd->Viewport = wp_viewporter_get_viewport(bd->Viewporter, vd->Surface);
        // Set initial destination size - this tells compositor the logical size
        // The Vulkan swapchain will be created at physical size (logical * scale)
        // and the compositor will scale it to fit the logical destination
        wp_viewport_set_destination(vd->Viewport, (int32_t)vd->Width, (int32_t)vd->Height);
    }

    // Check if we should initiate a toplevel drag for this new window
    // Use ImGui's mouse state as it's more reliable than our tracking during frame transitions
    ImGuiIO& io = ImGui::GetIO();
    bool mouse_down = io.MouseDown[0] || (bd->MouseButtonsDown != 0);
    bool should_drag = mouse_down && ImGui_ImplWayland_HasToplevelDragSupport() && (bd->PointerSerial != 0);
    printf("[Drag] CreateWindow: MouseButtonsDown=%d, io.MouseDown[0]=%d, PointerSerial=%u, should_drag=%d\n",
           bd->MouseButtonsDown, io.MouseDown[0], bd->PointerSerial, should_drag);

    // Commit surface to trigger configure sequence (this maps the surface)
    wl_surface_commit(vd->Surface);

    // Wait for configure event
    while (!vd->Configured)
        wl_display_roundtrip(bd->Display);

    // Store surface as platform handle
    viewport->PlatformHandle = (void*)vd->Surface;

    // Start the drag AFTER the surface is configured and mapped
    // GNOME requires the surface to be a valid drop target before starting drag
    if (should_drag)
    {
        // Calculate offset using local surface coordinates from the source surface
        // The offset is relative to the toplevel geometry being attached
        int32_t x_offset = (int32_t)bd->MouseLocalX;
        int32_t y_offset = (int32_t)bd->MouseLocalY;

        printf("[Drag] Starting toplevel drag (post-configure): offset=(%d, %d), PointerSerial=%u, MouseSurface=%p\n",
               x_offset, y_offset, bd->PointerSerial, (void*)bd->MouseSurface);

        // Start the drag operation - attaching the already-mapped toplevel
        bool drag_started = ImGui_ImplWayland_StartToplevelDrag(vd->Toplevel, x_offset, y_offset);
        printf("[Drag] StartToplevelDrag returned: %d\n", drag_started);
    }
}

static void ImGui_ImplWayland_DestroyWindow(ImGuiViewport* viewport)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr)
        return;

    // If this toplevel was being dragged, clean up the drag
    if (bd && bd->DraggedToplevel == vd->Toplevel)
    {
        bd->DraggedToplevel = nullptr;
        // The toplevel drag will be automatically cleaned up when the toplevel is destroyed
    }

    if (vd->WindowOwned)
    {
        if (vd->FrameCallback)
            wl_callback_destroy(vd->FrameCallback);
        if (vd->Viewport)
            wp_viewport_destroy(vd->Viewport);
        if (vd->FractionalScale)
            wp_fractional_scale_v1_destroy(vd->FractionalScale);
        if (vd->Toplevel)
            xdg_toplevel_destroy(vd->Toplevel);
        if (vd->XdgSurface)
            xdg_surface_destroy(vd->XdgSurface);
        if (vd->Surface)
            wl_surface_destroy(vd->Surface);
    }

    IM_DELETE(vd);
    viewport->PlatformUserData = nullptr;
    viewport->PlatformHandle = nullptr;
}

static void ImGui_ImplWayland_ShowWindow(ImGuiViewport* viewport)
{
    // Wayland windows are shown implicitly when the first buffer is committed
    // Nothing to do here
    (void)viewport;
}

static void ImGui_ImplWayland_SetWindowPos(ImGuiViewport* viewport, ImVec2 pos)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr)
        return;

    // During a toplevel drag, the compositor controls the window position.
    // Ignore SetWindowPos calls for the dragged toplevel - they come from ImGui
    // trying to sync position, but the compositor is in charge during drag.
    if (bd && bd->DragInProgress && bd->DraggedToplevel == vd->Toplevel)
    {
        // Don't update position during drag - the compositor handles it
        return;
    }

    // Ignore obviously bogus positions (INT_MIN converted to float)
    if (pos.y < -1000000.0f || pos.x < -1000000.0f)
    {
        return;
    }

    // Wayland does not allow clients to set window position directly.
    // However, we can use xdg_toplevel_drag to move existing windows.
    // Per protocol: "Dragging an existing window is similar. The client creates
    // a xdg_toplevel_drag_v1 object and attaches the existing toplevel before
    // starting the drag."
    //
    // Important: Only try once per drag operation. If the drag was cancelled,
    // don't retry until a new button press (new serial).
    bool dominated_by_drag = bd && bd->MouseButtonsDown != 0 && !bd->DragInProgress && !bd->DragFinished &&
        vd->Toplevel && ImGui_ImplWayland_HasToplevelDragSupport();

    // Debug: Log why we might not start a drag
    static int setpos_count = 0;
    if (++setpos_count % 60 == 1 || dominated_by_drag)
    {
        printf("[SetWindowPos] viewport=%p, pos=(%.1f,%.1f), MouseButtonsDown=%d, DragInProgress=%d, DragFinished=%d, Toplevel=%p, should_drag=%d\n",
               (void*)viewport, pos.x, pos.y,
               bd ? bd->MouseButtonsDown : -1,
               bd ? bd->DragInProgress : -1,
               bd ? bd->DragFinished : -1,
               (void*)vd->Toplevel,
               dominated_by_drag);
    }

    if (dominated_by_drag)
    {
        // Calculate offset: use local surface coordinates (relative to toplevel geometry)
        // This matches how Chromium passes offsets to xdg_toplevel_drag_v1_attach
        int32_t x_offset = (int32_t)bd->MouseLocalX;
        int32_t y_offset = (int32_t)bd->MouseLocalY;

        printf("[SetWindowPos] Starting drag for viewport %p with local offset (%d, %d)\n",
               (void*)viewport, x_offset, y_offset);

        if (ImGui_ImplWayland_StartToplevelDrag(vd->Toplevel, x_offset, y_offset))
        {
            // Drag started - don't update position, compositor handles it
            return;
        }
        else
        {
            // If start failed, mark as finished so we don't keep retrying
            bd->DragFinished = true;
        }
    }

    // Track the position that ImGui wants internally so that
    // GetWindowPos can return it and input coordinate transformations work.
    vd->PosX = pos.x;
    vd->PosY = pos.y;
}

static ImVec2 ImGui_ImplWayland_GetWindowPos(ImGuiViewport* viewport)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr)
        return ImVec2(0, 0);

    // Return the tracked position. For secondary viewports being dragged via
    // xdg_toplevel_drag, this is updated based on pointer motion.
    // Note: Wayland doesn't expose actual window position, so this is our best estimate.
    return ImVec2(vd->PosX, vd->PosY);
}

static void ImGui_ImplWayland_SetWindowSize(ImGuiViewport* viewport, ImVec2 size)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr)
        return;

    // Request specific size by setting min and max to the same value
    // Note: The compositor may not honor this request
    vd->IgnoreWindowSizeEventFrame = ImGui::GetFrameCount();

    // Update tracked size - the Vulkan backend will use this when rendering
    // Note: On Wayland, we can't directly resize windows from the client.
    // The compositor controls window size. We track what ImGui wants and
    // respond to compositor configure events.
    if (vd->Toplevel)
    {
        // Update our tracked size (used by GetWindowSize and Vulkan swapchain)
        vd->Width = (uint32_t)size.x;
        vd->Height = (uint32_t)size.y;
        vd->PendingResize = true;

        // Update viewporter destination if available
        if (vd->Viewport)
            wp_viewport_set_destination(vd->Viewport, (int32_t)size.x, (int32_t)size.y);
    }
}

static ImVec2 ImGui_ImplWayland_GetWindowSize(ImGuiViewport* viewport)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr)
        return ImVec2(0, 0);
    return ImVec2((float)vd->Width, (float)vd->Height);
}

static void ImGui_ImplWayland_SetWindowTitle(ImGuiViewport* viewport, const char* title)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr || vd->Toplevel == nullptr)
        return;
    xdg_toplevel_set_title(vd->Toplevel, title);
}

static void ImGui_ImplWayland_SetWindowFocus(ImGuiViewport* viewport)
{
    // Wayland does not allow clients to steal focus
    // This would require xdg_activation_v1 protocol with a valid activation token
    (void)viewport;
}

static float ImGui_ImplWayland_GetWindowDpiScale(ImGuiViewport* viewport)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr)
        return 1.0f;
    // Scale is in 120ths (e.g., 192 = 1.6x, 120 = 1.0x)
    return (float)vd->Scale / 120.0f;
}

static ImVec2 ImGui_ImplWayland_GetWindowFramebufferScale(ImGuiViewport* viewport)
{
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr)
        return ImVec2(1.0f, 1.0f);
    // Framebuffer scale is the ratio of buffer pixels to logical pixels
    // Scale is in 120ths (e.g., 192 = 1.6x, 120 = 1.0x)
    float scale = (float)vd->Scale / 120.0f;
    return ImVec2(scale, scale);
}

