// Vulkan surface creation for secondary viewports
// If IMGUI_IMPL_WAYLAND_HAS_VULKAN is defined, we can create Vulkan surfaces directly
// Otherwise, the application needs to override Platform_CreateVkSurface
#if defined(IMGUI_IMPL_WAYLAND_HAS_VULKAN) && defined(VK_USE_PLATFORM_WAYLAND_KHR)
static int ImGui_ImplWayland_CreateVkSurface(ImGuiViewport* viewport, ImU64 vk_instance, const void* vk_allocator, ImU64* out_vk_surface)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    ImGui_ImplWayland_ViewportData* vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
    if (vd == nullptr || vd->Surface == nullptr)
        return -1;

    VkWaylandSurfaceCreateInfoKHR info = {};
    info.sType = VK_STRUCTURE_TYPE_WAYLAND_SURFACE_CREATE_INFO_KHR;
    info.display = bd->Display;
    info.surface = vd->Surface;
    VkResult err = vkCreateWaylandSurfaceKHR((VkInstance)vk_instance, &info, (const VkAllocationCallbacks*)vk_allocator, (VkSurfaceKHR*)out_vk_surface);
    return (int)err;
}
#else
static int ImGui_ImplWayland_CreateVkSurface(ImGuiViewport* viewport, ImU64 vk_instance, const void* vk_allocator, ImU64* out_vk_surface)
{
    // Without Vulkan headers, this function cannot be implemented
    // The application should override Platform_CreateVkSurface in ImGuiPlatformIO
    (void)viewport;
    (void)vk_instance;
    (void)vk_allocator;
    (void)out_vk_surface;
    IM_ASSERT(0 && "Platform_CreateVkSurface not implemented. Define IMGUI_IMPL_WAYLAND_HAS_VULKAN and VK_USE_PLATFORM_WAYLAND_KHR, or override Platform_CreateVkSurface in your application.");
    return -1;
}
#endif // IMGUI_IMPL_WAYLAND_HAS_VULKAN

