// Update ImGui monitors list from tracked outputs
static void ImGui_ImplWayland_UpdateMonitors()
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    if (!bd || !bd->MonitorsDirty)
        return;

    ImGuiPlatformIO& platform_io = ImGui::GetPlatformIO();
    platform_io.Monitors.resize(0);

    for (int i = 0; i < bd->Outputs.Size; i++)
    {
        ImGui_ImplWayland_OutputData* od = bd->Outputs[i];
        if (!od->Done || od->Width <= 0 || od->Height <= 0)
            continue;

        ImGuiPlatformMonitor monitor;
        monitor.MainPos = ImVec2((float)od->PosX, (float)od->PosY);
        monitor.MainSize = ImVec2((float)od->Width, (float)od->Height);
        monitor.WorkPos = monitor.MainPos;
        monitor.WorkSize = monitor.MainSize;
        monitor.DpiScale = (float)od->Scale;
        platform_io.Monitors.push_back(monitor);
    }

    // Fallback: if no outputs tracked, create a default monitor from main viewport
    if (platform_io.Monitors.Size == 0)
    {
        ImGuiPlatformMonitor monitor;
        monitor.MainPos = ImVec2(0, 0);
        monitor.MainSize = ImVec2((float)bd->DisplayWidth, (float)bd->DisplayHeight);
        monitor.WorkPos = monitor.MainPos;
        monitor.WorkSize = monitor.MainSize;
        monitor.DpiScale = (float)bd->FractionalScale / 120.0f;
        platform_io.Monitors.push_back(monitor);
    }

    bd->MonitorsDirty = false;
}

//-----------------------------------------------------------------------------
// Toplevel Drag Support (xdg-toplevel-drag-v1)
// This allows viewports to follow the cursor when being dragged (undocked from dockspace)
//-----------------------------------------------------------------------------

// Data source listeners for toplevel drag
static void ImGui_ImplWayland_DataSourceTarget(void* /*data*/, struct wl_data_source* /*source*/, const char* /*mime_type*/)
{
    // Not used for toplevel drag - we don't actually transfer data
}

static void ImGui_ImplWayland_DataSourceSend(void* /*data*/, struct wl_data_source* /*source*/, const char* /*mime_type*/, int32_t fd)
{
    // Close the fd - we don't actually send data for toplevel drags
    close(fd);
}

static void ImGui_ImplWayland_DataSourceCancelled(void* data, struct wl_data_source* source)
{
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;

    // For xdg_toplevel_drag, "cancelled" often means the drag ended without a valid
    // drop target, but the window was still moved successfully by the compositor.
    // This is especially common on GNOME when dropping in empty space or when the
    // pointer leaves all surfaces briefly during the drag.
    bool was_toplevel_drag = (bd->ActiveToplevelDrag != nullptr);
    printf("[Drag] DataSourceCancelled called - was_toplevel_drag=%d\n", was_toplevel_drag);

    if (was_toplevel_drag)
    {
        // For toplevel drags, "cancelled" is often a successful window move
        // The compositor has already positioned the window where we want it
        printf("[Drag] Treating cancelled toplevel drag as successful window move\n");
    }

    // Clean up the data offer
    if (bd->CurrentDataOffer)
    {
        wl_data_offer_destroy(bd->CurrentDataOffer);
        bd->CurrentDataOffer = nullptr;
    }

    // Clean up the drag
    if (bd->ActiveToplevelDrag)
    {
        xdg_toplevel_drag_v1_destroy(bd->ActiveToplevelDrag);
        bd->ActiveToplevelDrag = nullptr;
    }
    if (source == bd->ActiveDataSource)
    {
        wl_data_source_destroy(source);
        bd->ActiveDataSource = nullptr;
    }
    bd->DraggedToplevel = nullptr;
    bd->DragEnterSurface = nullptr;
    bd->DragInProgress = false;
    bd->DragFinished = true;
}

static void ImGui_ImplWayland_DataSourceDndDropPerformed(void* data, struct wl_data_source* /*source*/)
{
    printf("[Drag] DataSourceDndDropPerformed\n");
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;

    // During DnD, the pointer is grabbed and button release events don't come through
    // wl_pointer - we must notify ImGui of the button release here so it can process
    // the drop action (e.g., dock a window).
    if (bd->DragInProgress)
    {
        ImGuiIO& io = ImGui::GetIO();

        // Ensure ImGui has the final mouse position and viewport before we release
        // Use the last known drag cursor position relative to the enter surface
        // Use viewport->Pos instead of vd->PosX/PosY since Wayland doesn't provide
        // reliable position info for secondary viewports
        if (bd->DragEnterSurface)
        {
            ImGuiViewport* viewport = ImGui_ImplWayland_FindViewportBySurface(bd->DragEnterSurface);
            if (viewport)
            {
                // CRITICAL: Tell ImGui which viewport we're over for docking to work
                io.AddMouseViewportEvent(viewport->ID);
                float global_x = viewport->Pos.x + (float)bd->DragCursorX;
                float global_y = viewport->Pos.y + (float)bd->DragCursorY;
                io.AddMousePosEvent(global_x, global_y);
                printf("[Drag] Final mouse pos: (%.1f, %.1f) (viewport pos: %.1f, %.1f), viewport_id=0x%X\n",
                       global_x, global_y, viewport->Pos.x, viewport->Pos.y, viewport->ID);
            }
        }

        io.AddMouseButtonEvent(0, false);  // Release left mouse button
        bd->MouseButtonsDown &= ~(1 << 0);
        printf("[Drag] Synthesized mouse button release\n");
    }

    // Drag finished - the toplevel's final position is determined by the compositor
    bd->DragFinished = true;
}

static void ImGui_ImplWayland_DataSourceDndFinished(void* data, struct wl_data_source* source)
{
    printf("[Drag] DataSourceDndFinished called - drop completed successfully\n");
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;

    // Clean up the data offer
    if (bd->CurrentDataOffer)
    {
        wl_data_offer_destroy(bd->CurrentDataOffer);
        bd->CurrentDataOffer = nullptr;
    }

    // Clean up after successful drop
    if (bd->ActiveToplevelDrag)
    {
        xdg_toplevel_drag_v1_destroy(bd->ActiveToplevelDrag);
        bd->ActiveToplevelDrag = nullptr;
    }
    if (source == bd->ActiveDataSource)
    {
        wl_data_source_destroy(source);
        bd->ActiveDataSource = nullptr;
    }
    bd->DraggedToplevel = nullptr;
    bd->DragEnterSurface = nullptr;
    bd->DragInProgress = false;
}

static void ImGui_ImplWayland_DataSourceAction(void* /*data*/, struct wl_data_source* /*source*/, uint32_t dnd_action)
{
    printf("[Drag] DataSourceAction: action=%u (none=%u, copy=%u, move=%u)\n",
           dnd_action, WL_DATA_DEVICE_MANAGER_DND_ACTION_NONE,
           WL_DATA_DEVICE_MANAGER_DND_ACTION_COPY, WL_DATA_DEVICE_MANAGER_DND_ACTION_MOVE);
}

static const struct wl_data_source_listener ImGui_ImplWayland_DataSourceListener = {
    .target = ImGui_ImplWayland_DataSourceTarget,
    .send = ImGui_ImplWayland_DataSourceSend,
    .cancelled = ImGui_ImplWayland_DataSourceCancelled,
    .dnd_drop_performed = ImGui_ImplWayland_DataSourceDndDropPerformed,
    .dnd_finished = ImGui_ImplWayland_DataSourceDndFinished,
    .action = ImGui_ImplWayland_DataSourceAction,
};

// Data device listeners (for receiving drag events)
static void ImGui_ImplWayland_DataDeviceDataOffer(void* data, struct wl_data_device* /*device*/, struct wl_data_offer* offer)
{
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;
    if (!bd || !offer)
        return;

    // During our own drag, we receive a new offer for each enter.
    // Track the most recent offer so we can clean it up properly.
    if (bd->DragInProgress)
    {
        if (bd->CurrentDataOffer && bd->CurrentDataOffer != offer)
        {
            wl_data_offer_destroy(bd->CurrentDataOffer);
        }
        bd->CurrentDataOffer = offer;
        return;
    }

    // When not dragging, this is likely a selection/clipboard offer.
    // We don't need to track these - they're managed by the compositor.
    // Don't destroy them either - the selection event will reference them.
}

static void ImGui_ImplWayland_DataDeviceEnter(void* data, struct wl_data_device* /*device*/, uint32_t serial, struct wl_surface* surface, wl_fixed_t x, wl_fixed_t y, struct wl_data_offer* offer)
{
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;
    if (!bd)
        return;

    // Find viewport for this surface
    ImGuiViewport* enter_vp = ImGui_ImplWayland_FindViewportBySurface(surface);
    ImGui_ImplWayland_ViewportData* enter_vd = enter_vp ? (ImGui_ImplWayland_ViewportData*)enter_vp->PlatformUserData : nullptr;

    double local_x = wl_fixed_to_double(x);
    double local_y = wl_fixed_to_double(y);

    printf("[Drag] DataDeviceEnter: surface=%p, pos=(%.1f, %.1f), offer=%p, DragInProgress=%d, viewport_pos=(%.1f, %.1f)\n",
           (void*)surface, local_x, local_y, (void*)offer, bd->DragInProgress,
           enter_vd ? enter_vd->PosX : -1.0f, enter_vd ? enter_vd->PosY : -1.0f);

    // Track the surface and position
    bd->DragEnterSurface = surface;
    bd->DragCursorX = local_x;
    bd->DragCursorY = local_y;

    // During our own drag, accept the offer to allow drop
    if (bd->DragInProgress && offer)
    {
        // Track this offer - each surface enter gives us a new one
        if (bd->CurrentDataOffer && bd->CurrentDataOffer != offer)
        {
            // Clean up old offer before tracking new one
            wl_data_offer_destroy(bd->CurrentDataOffer);
        }
        bd->CurrentDataOffer = offer;

        // Accept the offer to indicate we're a valid drop target
        wl_data_offer_accept(offer, serial, "application/x-imgui-viewport");
        wl_data_offer_set_actions(offer,
            WL_DATA_DEVICE_MANAGER_DND_ACTION_MOVE,
            WL_DATA_DEVICE_MANAGER_DND_ACTION_MOVE);

        // Immediately update ImGui mouse position and viewport on enter
        // This ensures dock previews appear as soon as we enter a target
        if (enter_vp && enter_vd)
        {
            ImGuiIO& io = ImGui::GetIO();
            // Tell ImGui which viewport the mouse is now over
            io.AddMouseViewportEvent(enter_vp->ID);
            float global_x = enter_vd->PosX + (float)local_x;
            float global_y = enter_vd->PosY + (float)local_y;
            io.AddMousePosEvent(global_x, global_y);
        }
    }
}

static void ImGui_ImplWayland_DataDeviceLeave(void* data, struct wl_data_device* /*device*/)
{
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;
    printf("[Drag] DataDeviceLeave: DragInProgress=%d\n", bd ? bd->DragInProgress : -1);
    if (bd)
    {
        bd->DragEnterSurface = nullptr;
    }
}

static void ImGui_ImplWayland_DataDeviceMotion(void* data, struct wl_data_device* /*device*/, uint32_t /*time*/, wl_fixed_t x, wl_fixed_t y)
{
    static int motion_count = 0;
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;
    if (!bd)
        return;

    bd->DragCursorX = wl_fixed_to_double(x);
    bd->DragCursorY = wl_fixed_to_double(y);

    // Log occasionally to avoid spam
    if (bd->DragInProgress && (++motion_count % 30 == 1))
        printf("[Drag] DataDeviceMotion: pos=(%.1f, %.1f), surface=%p\n",
               bd->DragCursorX, bd->DragCursorY, (void*)bd->DragEnterSurface);

    // During drag, update ImGui's mouse position based on the surface we're over
    // The coordinates are relative to the surface we entered
    if (bd->DragInProgress && bd->DragEnterSurface)
    {
        // Find the viewport for this surface
        ImGuiViewport* viewport = ImGui_ImplWayland_FindViewportBySurface(bd->DragEnterSurface);
        if (viewport)
        {
            ImGuiIO& io = ImGui::GetIO();

            // Check if we're over the viewport being dragged
            ImGuiViewport* dragged_vp = ImGui_ImplWayland_FindViewportByToplevel(bd->DraggedToplevel);
            bool over_dragged_viewport = (dragged_vp == viewport);

            // Check if this viewport has a reliable position (main viewport is at 0,0)
            bool is_main_viewport = (viewport->Flags & ImGuiViewportFlags_IsPlatformWindow) == 0;

            // Tell ImGui which viewport the mouse is over during drag
            io.AddMouseViewportEvent(viewport->ID);

            if (over_dragged_viewport)
            {
                // When cursor is over the dragged viewport itself, we can't use its
                // position to calculate global coords (feedback loop). Instead, use
                // the dragged viewport's last known position plus local cursor pos.
                // This lets ImGui track the drag even when over the dragged window.
                float global_x = dragged_vp->Pos.x + (float)bd->DragCursorX;
                float global_y = dragged_vp->Pos.y + (float)bd->DragCursorY;
                io.AddMousePosEvent(global_x, global_y);
                // Don't update dragged viewport position here - would cause feedback loop
            }
            else if (is_main_viewport)
            {
                // We're over the main viewport which has reliable position (0,0)
                float global_x = viewport->Pos.x + (float)bd->DragCursorX;
                float global_y = viewport->Pos.y + (float)bd->DragCursorY;
                io.AddMousePosEvent(global_x, global_y);

                // Update the dragged viewport's tracked position - this is reliable
                // because we're calculating from a known reference point
                ImGui_ImplWayland_UpdateDraggedViewportPosition(global_x, global_y);
            }
            else
            {
                // Over another secondary viewport - use tracked position from viewport data
                ImGui_ImplWayland_ViewportData* target_vd = (ImGui_ImplWayland_ViewportData*)viewport->PlatformUserData;
                float vp_x = target_vd ? target_vd->PosX : viewport->Pos.x;
                float vp_y = target_vd ? target_vd->PosY : viewport->Pos.y;
                float global_x = vp_x + (float)bd->DragCursorX;
                float global_y = vp_y + (float)bd->DragCursorY;
                io.AddMousePosEvent(global_x, global_y);
            }
        }
    }
}

static void ImGui_ImplWayland_DataDeviceDrop(void* data, struct wl_data_device* /*device*/)
{
    printf("[Drag] DataDeviceDrop\n");
    ImGui_ImplWayland_Data* bd = (ImGui_ImplWayland_Data*)data;
    if (!bd)
        return;

    // When we receive a drop event, we need to acknowledge it by calling finish()
    // on the current data offer. This signals to the source that the drop was
    // accepted, which triggers dnd_finished instead of cancelled.
    if (bd->CurrentDataOffer)
    {
        printf("[Drag] Calling wl_data_offer_finish on offer %p\n", (void*)bd->CurrentDataOffer);
        wl_data_offer_finish(bd->CurrentDataOffer);
        // Don't destroy the offer here - it will be cleaned up in dnd_finished/cancelled
    }
}

static void ImGui_ImplWayland_DataDeviceSelection(void* /*data*/, struct wl_data_device* /*device*/, struct wl_data_offer* /*offer*/)
{
    // Selection/clipboard offer - we don't handle clipboard, so ignore this.
    // The offer is managed by the compositor for clipboard operations.
}

static const struct wl_data_device_listener ImGui_ImplWayland_DataDeviceListener = {
    .data_offer = ImGui_ImplWayland_DataDeviceDataOffer,
    .enter = ImGui_ImplWayland_DataDeviceEnter,
    .leave = ImGui_ImplWayland_DataDeviceLeave,
    .motion = ImGui_ImplWayland_DataDeviceMotion,
    .drop = ImGui_ImplWayland_DataDeviceDrop,
    .selection = ImGui_ImplWayland_DataDeviceSelection,
};

// Start a toplevel drag for an existing toplevel window
// This attaches the toplevel to the current pointer and makes it follow the cursor
// Returns true if the drag was started successfully
static bool ImGui_ImplWayland_StartToplevelDrag(struct xdg_toplevel* toplevel, int32_t x_offset, int32_t y_offset)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    if (!bd || !bd->ToplevelDragManager || !bd->DataDeviceManager || !bd->Seat)
    {
        printf("[Drag] StartToplevelDrag: missing globals (bd=%p, ToplevelDragManager=%p, DataDeviceManager=%p, Seat=%p)\n",
               (void*)bd, bd ? (void*)bd->ToplevelDragManager : nullptr,
               bd ? (void*)bd->DataDeviceManager : nullptr, bd ? (void*)bd->Seat : nullptr);
        return false;
    }

    // Don't start a new drag if one is already in progress
    if (bd->DragInProgress)
    {
        printf("[Drag] StartToplevelDrag: drag already in progress\n");
        return false;
    }

    // Need a valid pointer serial from a button press
    if (bd->PointerSerial == 0)
    {
        printf("[Drag] StartToplevelDrag: no valid PointerSerial\n");
        return false;
    }

    // Create data device if not already done
    if (!bd->DataDevice)
    {
        bd->DataDevice = wl_data_device_manager_get_data_device(bd->DataDeviceManager, bd->Seat);
        wl_data_device_add_listener(bd->DataDevice, &ImGui_ImplWayland_DataDeviceListener, bd);
    }

    // Create a data source for the drag
    bd->ActiveDataSource = wl_data_device_manager_create_data_source(bd->DataDeviceManager);
    if (!bd->ActiveDataSource)
        return false;

    wl_data_source_add_listener(bd->ActiveDataSource, &ImGui_ImplWayland_DataSourceListener, bd);

    // Offer MIME types (required even though we don't transfer data)
    wl_data_source_offer(bd->ActiveDataSource, "application/x-imgui-viewport");
    // rootwindow-drop allows dropping on the desktop/root window in GNOME
    // This prevents the drag from being cancelled when the cursor leaves all surfaces
    wl_data_source_offer(bd->ActiveDataSource, "application/x-rootwindow-drop");

    // Set allowed DnD actions - MOVE is most appropriate for window dragging
    wl_data_source_set_actions(bd->ActiveDataSource,
        WL_DATA_DEVICE_MANAGER_DND_ACTION_MOVE);

    // Create the toplevel drag object (but don't attach yet - Chromium does attach after start_drag)
    bd->ActiveToplevelDrag = xdg_toplevel_drag_manager_v1_get_xdg_toplevel_drag(bd->ToplevelDragManager, bd->ActiveDataSource);
    if (!bd->ActiveToplevelDrag)
    {
        wl_data_source_destroy(bd->ActiveDataSource);
        bd->ActiveDataSource = nullptr;
        return false;
    }

    printf("[Drag] About to start_drag: MouseSurface=%p, PointerSerial=%u\n",
           (void*)bd->MouseSurface, bd->PointerSerial);

    // Start the drag FIRST - origin surface is where the drag starts from
    // The icon surface is nullptr (no drag icon)
    wl_data_device_start_drag(bd->DataDevice, bd->ActiveDataSource, bd->MouseSurface, nullptr, bd->PointerSerial);

    // Now attach the toplevel to the drag AFTER starting
    // This matches Chromium's implementation order
    // The offset is relative to the toplevel's geometry (surface-local coordinates)
    printf("[Drag] Attaching toplevel %p with offset (%d, %d)\n", (void*)toplevel, x_offset, y_offset);
    xdg_toplevel_drag_v1_attach(bd->ActiveToplevelDrag, toplevel, x_offset, y_offset);
    bd->DraggedToplevel = toplevel;
    bd->DragOffsetX = x_offset;
    bd->DragOffsetY = y_offset;

    // Flush to ensure the commands are sent immediately
    wl_display_flush(bd->Display);

    bd->DragInProgress = true;
    bd->DragFinished = false;

    printf("[Drag] Drag started, waiting for compositor response\n");

    return true;
}

// Check if toplevel drag is supported
static bool ImGui_ImplWayland_HasToplevelDragSupport()
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    return bd && bd->ToplevelDragManager && bd->DataDeviceManager && bd->Seat;
}

// Public API: Add output for tracking
void ImGui_ImplWayland_AddOutput(struct wl_output* output, uint32_t name)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    if (!bd)
        return;

    ImGui_ImplWayland_OutputData* od = IM_NEW(ImGui_ImplWayland_OutputData)();
    od->Output = output;
    od->Name = name;
    bd->Outputs.push_back(od);

    // Add wl_output listener
    wl_output_add_listener(output, &ImGui_ImplWayland_OutputListener, od);

    // If xdg-output manager is available, also get xdg-output
    if (bd->XdgOutputManager)
    {
        od->XdgOutput = zxdg_output_manager_v1_get_xdg_output(bd->XdgOutputManager, output);
        zxdg_output_v1_add_listener(od->XdgOutput, &ImGui_ImplWayland_XdgOutputListener, od);
    }

    bd->MonitorsDirty = true;
}

// Public API: Remove output from tracking
void ImGui_ImplWayland_RemoveOutput(uint32_t name)
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    if (!bd)
        return;

    for (int i = 0; i < bd->Outputs.Size; i++)
    {
        if (bd->Outputs[i]->Name == name)
        {
            ImGui_ImplWayland_OutputData* od = bd->Outputs[i];
            if (od->XdgOutput)
                zxdg_output_v1_destroy(od->XdgOutput);
            if (od->Output)
                wl_output_destroy(od->Output);
            IM_DELETE(od);
            bd->Outputs.erase(&bd->Outputs[i]);
            bd->MonitorsDirty = true;
            break;
        }
    }
}

// Public API: Get the serial from the most recent pointer enter event
// This is needed for wp_cursor_shape_device_v1_set_shape()
uint32_t ImGui_ImplWayland_GetPointerEnterSerial()
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();
    if (!bd)
        return 0;
    return bd->PointerEnterSerial;
}

static void ImGui_ImplWayland_InitMultiViewportSupport()
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();

    // Register platform interface (will be coupled with a renderer interface)
    ImGuiPlatformIO& platform_io = ImGui::GetPlatformIO();
    platform_io.Platform_CreateWindow = ImGui_ImplWayland_CreateWindow;
    platform_io.Platform_DestroyWindow = ImGui_ImplWayland_DestroyWindow;
    platform_io.Platform_ShowWindow = ImGui_ImplWayland_ShowWindow;
    platform_io.Platform_SetWindowPos = ImGui_ImplWayland_SetWindowPos;
    platform_io.Platform_GetWindowPos = ImGui_ImplWayland_GetWindowPos;
    platform_io.Platform_SetWindowSize = ImGui_ImplWayland_SetWindowSize;
    platform_io.Platform_GetWindowSize = ImGui_ImplWayland_GetWindowSize;
    platform_io.Platform_SetWindowFocus = ImGui_ImplWayland_SetWindowFocus;
    platform_io.Platform_GetWindowFocus = ImGui_ImplWayland_GetWindowFocus;
    platform_io.Platform_GetWindowMinimized = ImGui_ImplWayland_GetWindowMinimized;
    platform_io.Platform_SetWindowTitle = ImGui_ImplWayland_SetWindowTitle;
    platform_io.Platform_GetWindowDpiScale = ImGui_ImplWayland_GetWindowDpiScale;
    platform_io.Platform_GetWindowFramebufferScale = ImGui_ImplWayland_GetWindowFramebufferScale;
    platform_io.Platform_CreateVkSurface = ImGui_ImplWayland_CreateVkSurface;

    // Register main window handle (which is owned by the main application, not by us)
    // This is mostly for simplicity and consistency, so that our code can use same logic for main and secondary viewports.
    ImGuiViewport* main_viewport = ImGui::GetMainViewport();
    ImGui_ImplWayland_ViewportData* vd = IM_NEW(ImGui_ImplWayland_ViewportData)();
    vd->Surface = bd->MainSurface;
    vd->Width = bd->DisplayWidth;
    vd->Height = bd->DisplayHeight;
    vd->Scale = bd->FractionalScale;
    vd->Configured = true;
    vd->WindowOwned = false;  // Main window is owned by the application
    main_viewport->PlatformUserData = vd;
    main_viewport->PlatformHandle = (void*)bd->MainSurface;

    // Initialize monitors - mark as dirty so UpdateMonitors will populate the list
    // If no outputs are registered via AddOutput(), we'll use a fallback monitor
    bd->MonitorsDirty = true;
    ImGui_ImplWayland_UpdateMonitors();
}

static void ImGui_ImplWayland_ShutdownMultiViewportSupport()
{
    ImGui_ImplWayland_Data* bd = ImGui_ImplWayland_GetBackendData();

    // Clean up output tracking
    for (int i = 0; i < bd->Outputs.Size; i++)
    {
        ImGui_ImplWayland_OutputData* od = bd->Outputs[i];
        if (od->XdgOutput)
            zxdg_output_v1_destroy(od->XdgOutput);
        // Don't destroy wl_output - it's owned by the application
        IM_DELETE(od);
    }
    bd->Outputs.clear();

    ImGui::DestroyPlatformWindows();
}

#else // !IMGUI_IMPL_WAYLAND_USE_XDG_SHELL

