static void ImGui_ImplWayland_InitMultiViewportSupport()
{
    // Multi-viewport not available without xdg-shell protocol
    IM_ASSERT(0 && "Multi-viewport requires IMGUI_IMPL_WAYLAND_USE_XDG_SHELL to be defined");
}

static void ImGui_ImplWayland_ShutdownMultiViewportSupport()
{
}

